sql:
SELECT course_id, AVG(rating) AS average_rating
FROM course_reviews
GROUP BY course_id;

SELECT courses.title, courses.description, categories.category_name
FROM courses
INNER JOIN categories ON courses.category_id = categories.category_id;

SELECT AVG(enrolled_students) AS average_enrollment
FROM courses
WHERE category_id = 5;

external_knowledge:
- "blossoming gardens" refers to active courses;
- "sprouted beneath the $50 threshold" means courses with a price less than $50;
- "nurtured by their gardeners" refers to teachers who created the courses;
- "tended to by more than a dozen blossoms" implies more than 10 students are enrolled;
- "basking in the radiant sunshine" signifies that the course status is 'Active';
- "scents" metaphorically represents the average rating of the courses.

sql:
SELECT courses.title, teachers.teacher_name
FROM courses
JOIN teachers ON courses.teacher_id = teachers.teacher_id;

external_knowledge:
- "broad and specific categories" refers to the category and subcategory of the courses;
- "who teaches them" refers to the teacher's name;
- "how many students are in each" refers to the number of enrolled students.

sql:
SELECT AVG(course_reviews.rating) AS AverageRating
FROM courses
JOIN course_reviews ON courses.course_id = course_reviews.course_id
WHERE courses.enrolled_students = (
    SELECT MAX(enrolled_students) FROM courses
);

SELECT course_id, average_rating
FROM course_ratings
ORDER BY average_rating DESC;

